// Script Continued Below
/*jshint esnext: true */
(function executeRule(current, previous /*null when async*/ ) {

	// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
	// Script Continued Below

	var grRole;
	var grUser = new GlideRecordSecure("x_153465_discovert_organization_user");
	var UserPermissions = new UserInfoScripts();
	var userName = current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name;

	// STRY0076016
	if(!UserPermissions.userCanCreateMem(current.discover_office_hierarchy)){
		gs.addInfoMessage('Action not authorized');
		current.setAbortAction(true);
		return;
	}

	var tasker_user = current.getValue("u_organizational_user");
	if(!grUser.get(tasker_user)){
		// we will have to see what happens here
		grUser.u_tasker_user = current.getValue("office_member");
		grUser.insert();
	} else{
		if(grUser.active == false){
			grUser.active = true;
		}
		if(current.getDisplayValue("u_default_ou")==''){
			UserPermissions.setNewDefaultOU(current.u_tasker_user);
		}
		grUser.update();
	}	
	// RJ : Updated condition to changesTo() on 13-Sep-20
	//-----------------------------------------------------------------------------------------------------
	// Role: OU Template Designer -
		// NOTE: this is not a role any more, but it does require adding 
		// x_153465_discovert.tasker_process_template_user
	//-----------------------------------------------------------------------------------------------------
	// Add Role
	if (current.has_ou_process_rights) {
		UserPermissions.addRole(current.office_member, userName, 'x_153465_discovert.tasker_process_template_user');
	}
})(current, previous);
